sql:
SELECT device_name
FROM fpga_devices
ORDER BY device_name;

SELECT device_name
FROM fpga_devices
ORDER BY device_name;

SELECT pin_id
FROM pin_usage
WHERE usage_count = (SELECT MAX(usage_count) FROM pin_usage);

SELECT MAX(timestamp) AS latest_configuration_change_time
FROM device_history
WHERE device_id = 1;

SELECT AVG(usage_count) AS average_usage
FROM pin_usage
WHERE usage_count > 5;

SELECT device_model
FROM fpga_devices
ORDER BY device_model ASC;

SELECT pin_id, usage_count
FROM pin_usage
ORDER BY usage_count DESC;

SELECT usage_count
FROM pin_usage
WHERE pin_id = 1;

SELECT SUM(usage_count) AS total_usage
FROM pin_usage
WHERE pin_id = 1;

SELECT conflict_type
FROM conflict_detection
WHERE device_id = 0;

SELECT MAX(connection_speed) AS max_speed
FROM connections
WHERE device_name = 'XC2V80';

